<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-radius-lg:   0.5rem;   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 8px  */</span></span>
